using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    Models.SummarizeResponse Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization: scores sentences by word frequency and
/// returns the top-ranked sentences in their original order.
/// </summary>
public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","in","on","at","to","for","of","with",
        "by","from","is","are","was","were","be","been","being","have","has",
        "had","do","does","did","will","would","shall","should","may","might",
        "can","could","this","that","these","those","it","its","i","we","you",
        "he","she","they","me","him","her","us","them","my","your","his","our",
        "their","not","no","so","if","as","up","out","about","into","over",
        "after","then","than","too","very","just","also","more","some","any",
        "all","each","every","both","few","many","much","own","other","such"
    };

    public SummarizeResponse Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences, preserving original order.
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = topIndices.Count
        };
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text.Trim())
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (!StopWords.Contains(word))
                {
                    freq[word] = freq.GetValueOrDefault(word) + 1;
                }
            }
        }

        return freq;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Count > 0 ? wordFrequencies.Values.Max() : 1;
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = TokenizeWords(sentence);
            if (words.Count == 0)
            {
                scores.Add(0);
                continue;
            }

            double total = words
                .Where(w => !StopWords.Contains(w) && wordFrequencies.ContainsKey(w))
                .Sum(w => (double)wordFrequencies[w] / maxFreq);

            scores.Add(total / words.Count);
        }

        return scores;
    }

    private static List<string> TokenizeWords(string sentence)
    {
        return WordRegex()
            .Matches(sentence)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z0-9']+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = _summaryService.Summarize(request.Text, request.MaxSentences);
        return Ok(result);
    }
}

